import { CCol, CForm, CFormInput, CContainer, CRow, CFormLabel, CButton } from '@coreui/react';
import React, { useState } from 'react';
import TextArea from '../common/TextArea';

const MagazineComponent = () => {
    const [formData, setFormData] = useState({ title: '', article: '', file: null });

    // Function to handle changes in form fields
    const handleChange = (e) => {
        const { name, value, files } = e.target;
        if (name === 'file') {
            // Handle file input
            const file = files[0];
            setFormData({...formData, [name]: file });

            // If you need to convert the file into a byte array, you can use FileReader
            const reader = new FileReader();
            reader.onloadend = () => {
                const byteArray = new Uint8Array(reader.result);
                console.log("File as byte array:", byteArray);
                // You can now store or send this byteArray as per your need
            };
            reader.readAsArrayBuffer(file);
        } else {
            setFormData({...formData, [name]: value });
        }
    };

    // Function to handle form submission
    const handleSubmit = (e) => {
        e.preventDefault();
        console.log('FormDataSubmitted:', formData);
        // Form data (including the file) can now be sent to your server
    };

    return (
        <CContainer className="d-flex justify-content-center align-items-center" style={{ minHeight: '50vh' }}>
            <CRow className="w-90">
                {/* Title Input */}
                <CCol md={12}>
                    <CFormLabel htmlFor="formFile">Title<span className="text-danger">*</span></CFormLabel>
                    <CForm>
                        <CFormInput
                            id="exampleFormControlInput1"
                            placeholder="Enter title"
                            name="title"
                            value={formData.title}
                            onChange={handleChange}
                        />
                    </CForm>
                </CCol>

                {/* Article TextArea */}
                <CCol md={12}>
                    <TextArea
                        value={formData.article}
                        label="Article"
                        required
                        name="article"
                        onChange={handleChange}
                        placeholder="Write your article here"
                    />
                </CCol>

                {/* File Input */}
                <CCol md={12}>
                    <div>
                        <CFormInput
                            type="file"
                            size="lg"
                            id="formFileLg"
                            label="Large file input example"
                            name="file"
                            onChange={handleChange}
                        />
                    </div>
                </CCol>

                {/* Submit Button */}
                <CCol md={12} className="mt-3">
                    <CButton color="primary" onClick={handleSubmit}>
                        Submit
                    </CButton>
                </CCol>
            </CRow>
        </CContainer>
    );
};

export default MagazineComponent;
